require(['app'], function(app){
app.views.index=Backbone.View.extend({
    initialize:function(){
        console.log("initializing index view");
         //this.auth();
    },
	
    render:function(){
        $(this.el).html(this.template());
        
        
      
        var down = {};
        document.addEventListener("keyup", function( ev ) {
            if ( down[16] && down[76] && down[73] ) {//shift+l+i
                document.location.href = "#lang/it";
            }
            if (down[16] && down[76] && down[68]) {//shift+l+d
                document.location.href = "#lang/de";
            }
                down[ev.keyCode] = false;

        });


        document.addEventListener("keydown", function( ev ) {
  
            down[ev.keyCode] = true;
   

        }, false);
        this.$("#temp_short_title").html(app.global.app_short_name);
	    
        this.$("#temp_long_title").html(app.global.app_long_name);
       // app.global.versionsCollection.add(app.const.version.responseText);
		
        $(document).attr("title",app.global.app_short_name+" - "+app.global.app_long_name+" | "+this.language.type+" | "+this.language.lang);
        return this;
    },
            
  
    destroy_view:function(){
        
        this.undelegateEvents();
        $(this.el).removeData().unbind();
        this.remove();
        Backbone.View.prototype.remove.call(this);
        app.global.indexView=null;
       
    }
});
return app.views.index;
});
